// Evolution API envia o evento. Filtrar apenas mensagens recebidas de leads.
const body = $input.item.json.body || $input.item.json;

// Ignorar mensagens enviadas pelo próprio bot
const fromMe = body?.data?.key?.fromMe || body?.key?.fromMe || false;
if (fromMe) return [];

// Ignorar atualizações de status (não são mensagens)
const event = body?.event || '';
if (event !== 'messages.upsert') return [];

// Extrair telefone e texto
const remoteJid = body?.data?.key?.remoteJid || body?.key?.remoteJid || '';
const telefone  = remoteJid.replace('@s.whatsapp.net', '').replace(/\D/g, '');
const texto     = body?.data?.message?.conversation
               || body?.data?.message?.extendedTextMessage?.text
               || body?.message?.conversation
               || '';

if (!telefone || !texto) return [];

return [{ json: { telefone, texto, event_raw: body } }];

const leads   = $('Buscar Lead por Telefone').item.json;
const lead    = Array.isArray(leads) ? leads[0] : leads;
const texto   = $('Filtrar Mensagem Válida').item.json.texto;

// Adicionar mensagem ao histórico
const historico = lead.historico_conversa || [];
historico.push({ role: 'user', content: texto, ts: new Date().toISOString() });

const eraEmTentativa = ['tentativa_1','tentativa_2','tentativa_3'].includes(lead.estado);

return [{
  json: {
    lead,
    texto,
    historico,
    eraEmTentativa,
    historico_json: JSON.stringify(historico)
  }
}];

const prepData  = $('Preparar Lead e Histórico').item.json;
const lead      = prepData.lead;
const configs   = $('Buscar Config Cliente').item.json;
const clients   = $('Buscar Dados Cliente').item.json;

const config     = Array.isArray(configs) ? configs[0] : configs;
const clientRec  = Array.isArray(clients) ? clients[0] : clients;
const mapeamento = config?.crm_mapeamento || {};
const nomeFantasia = (clientRec?.nome_fantasia || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');

// Montar prompt BANT para Claude
// Prioridade: Budget (capacidade de investir) e Authority (quem decide)
const historico = prepData.historico;
const systemPrompt = `Você é um SDR de IA da ${clientRec?.razao_social || 'empresa'}. Analise a conversa e faça qualificação BANT com foco em Budget e Authority primeiro.

Resposta OBRIGATÓRIA em JSON:
{
  "acao": "qualificado" | "nao_qualificado" | "continuar" | "agendar",
  "resposta": "mensagem para enviar ao lead (em português, natural)",
  "bant_budget": "o que descobrimos sobre budget",
  "bant_authority": "o que descobrimos sobre quem decide",
  "bant_need": "qual a necessidade",
  "bant_timeline": "prazo",
  "motivo_perda": "motivo se nao_qualificado, senão null"
}

Regras:
- "qualificado": lead tem budget, é o decisor (ou influenciador), tem necessidade real
- "nao_qualificado": claramente sem budget, sem autoridade, sem fit
- "agendar": lead qualificado e PEDIU ou ACEITOU reunião — tente propor horário
- "continuar": ainda qualificando, precisa de mais informações
- Seja natural, humano, não robótico. Máximo 3 linhas por mensagem.
- Se o lead demonstrar interesse em reunião, use acao="agendar"`;

const messages = historico.map(h => ({
  role: h.role,
  content: h.content
}));

const claudePayload = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 1024,
  system: systemPrompt,
  messages
});

return [{
  json: {
    lead,
    config,
    mapeamento,
    instance_name:    nomeFantasia,
    historico:        prepData.historico,
    eraEmTentativa:   prepData.eraEmTentativa,
    claude_payload:   claudePayload,
    historico_json:   prepData.historico_json
  }
}];

const claudeResp    = $input.item.json;
const montar        = $('Montar Prompt BANT').item.json;

// Extrair texto da resposta do Claude
const rawText = claudeResp?.content?.[0]?.text || '{}';

let bant;
try {
  // Claude pode envolver o JSON em ```json ... ```
  const clean = rawText.replace(/```json\n?/g, '').replace(/```/g, '').trim();
  bant = JSON.parse(clean);
} catch(e) {
  bant = { acao: 'continuar', resposta: 'Pode me contar um pouco mais sobre sua situação?' };
}

// Adicionar resposta do SDR ao histórico
const historico = montar.historico || [];
historico.push({ role: 'assistant', content: bant.resposta, ts: new Date().toISOString() });

// Montar update do Supabase
const update = {
  historico_conversa: historico,
  ultima_acao_at:     new Date().toISOString(),
  // Parar cadência automaticamente quando respondeu
  proxima_acao:       null,
  proxima_acao_at:    null
};

if (bant.bant_budget)    update.bant_budget    = bant.bant_budget;
if (bant.bant_authority) update.bant_authority = bant.bant_authority;
if (bant.bant_need)      update.bant_need      = bant.bant_need;
if (bant.bant_timeline)  update.bant_timeline  = bant.bant_timeline;

if      (bant.acao === 'qualificado' || bant.acao === 'agendar') update.estado = 'qualificado';
else if (bant.acao === 'nao_qualificado')                         update.estado = 'nao_qualificado';
else                                                              update.estado = 'em_conversa';

if (bant.motivo_perda)   update.motivo_perda  = bant.motivo_perda;
if (bant.acao === 'qualificado' || bant.acao === 'agendar') update.qualificado = true;
if (bant.acao === 'nao_qualificado') update.qualificado = false;

const stageMap = {
  em_conversa:     montar.mapeamento.em_conversa,
  qualificado:     montar.mapeamento.em_conversa,    // permanece em conversa até reunião ser confirmada
  nao_qualificado: montar.mapeamento.nao_qualificado_ia,
  agendar:         montar.mapeamento.reuniao_agendada
};

return [{
  json: {
    lead:          montar.lead,
    config:        montar.config,
    mapeamento:    montar.mapeamento,
    instance_name: montar.instance_name,
    eraEmTentativa: montar.eraEmTentativa,
    bant,
    resposta:      bant.resposta,
    acao:          bant.acao,
    stageId:       stageMap[bant.acao === 'agendar' ? 'agendar' : update.estado] || null,
    supabase_update: JSON.stringify(update)
  }
}];
